%[text] # 例6.4（DHTの基底画像）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example06_07"; % mfilename

%imgname = "msipimg01";
%imgname = "msipimg07";
%imgfmt = "tiff";
%%
%[text] ## DHT基底ベクトル
J = 2;
M = 2^J;
H = dhtmtx(J);
figure(1) %[output:38063e69]
for idx = 1:M
    b = H(idx,:);
    subplot(M/2,2,idx) %[output:38063e69]
    stem(0:M-1,b,'k','fill')
    axis([0-.5 M-1+.5 -sqrt(2/M) sqrt(2/M)])
    xlabel('$n$','Interpreter','latex')
    %ylabel("${b}_"+num2str(idx-1)+"[n]$",'Interpreter','latex')
    title("$\mathbf{b}_"+num2str(idx-1)+"$",'Interpreter','latex')
    ax = gca;
    ax.FontSize = 12;
end
f = gcf;
exportgraphics(f,fullfile(resfolder,"fig06-05a.png")) %[output:38063e69]
%%
%[text] ## DHT基底画像
basisimgs = cell(M,M);
for iRow = 1:M
    for iCol = 1:M
        b1 = H(iCol,:).';
        b2 = H(iRow,:);
        basisimgs{iRow,iCol} = kron(b1,b2)+.5;
    end
end

figure(2) %[output:7811a3f6]
I = montage(basisimgs,'BorderSize',[2 2],'BackgroundColor','white','ThumbnailInterpolation','nearest',... %[output:group:58769f3d] %[output:7811a3f6] %[output:9c9fa84d]
    'ThumbnailSize',[20 20]) %[output:group:58769f3d] %[output:7811a3f6] %[output:9c9fa84d]
imwrite(I.CData,fullfile(resfolder,"fig06-05b.png"))

%%
%[text] ## DHT行列
function H = dhtmtx(J)
H = 1;
I = 1;
for j=1:J
    M = 2^j;
    H = 1/sqrt(2)*[kron(H,[1 1]); kron(I,[1 -1])];
    I = eye(M);
end
end
